def backfill_enoncedevoir(apps, schema_editor):
    """
    P2.3 : pour chaque Devoir, sans perte —
      - Devoir.enonce -> EnonceDevoir(ordre=1), toutes les QuestionDevoir
        existantes du devoir rattachées à cet énoncé 1.
      - chaque string de enonces_supplementaires -> EnonceDevoir(ordre=2, 3…),
        sans question rattachée (elles n'en avaient jamais dans l'ancien
        modèle JSON).
    """
    Devoir = apps.get_model('evaluation', 'Devoir')
    EnonceDevoir = apps.get_model('evaluation', 'EnonceDevoir')

    nb_devoirs, nb_enonces_supp, nb_questions_rattachees = 0, 0, 0

    for devoir in Devoir.objects.prefetch_related('questions'):
        enonce_principal = EnonceDevoir.objects.create(
            devoir=devoir, contenu=devoir.enonce or '', ordre=1
        )
        nb_devoirs += 1

        nb = devoir.questions.update(enonce_devoir=enonce_principal)
        nb_questions_rattachees += nb

        for i, contenu in enumerate(devoir.enonces_supplementaires or [], start=2):
            EnonceDevoir.objects.create(devoir=devoir, contenu=contenu, ordre=i)
            nb_enonces_supp += 1

    logger.info(
        "P2.3 : backfill EnonceDevoir — %s devoirs (énoncé ordre=1 créé), "
        "%s questions rattachées, %s énoncés supplémentaires éclatés depuis "
        "enonces_supplementaires (ordres 2+).",
        nb_devoirs, nb_questions_rattachees, nb_enonces_supp,
    )


